6433     // For each ashr, three cases:
6434     //   shift = 0 => unchanged value
6435     //   saturation => 0 or -1
6436     //   other => a value closer to zero (of the same sign)
6437     // Thus, the end value is closer to zero than the start.
6438     auto KnownEnd = KnownBits::ashr(KnownStart,
6439                                     KnownBits::makeConstant(TotalShift));
