6355 ConstantRange ScalarEvolution::
6356 getRangeForUnknownRecurrence(const SCEVUnknown *U) {
6357   const DataLayout &DL = getDataLayout();
6358 
6359   unsigned BitWidth = getTypeSizeInBits(U->getType());
6360   const ConstantRange FullSet(BitWidth, /*isFullSet=*/true);
6361 
6362   // Match a simple recurrence of the form: <start, ShiftOp, Step>, and then
6363   // use information about the trip count to improve our available range.  Note
6364   // that the trip count independent cases are already handled by known bits.
6365   // WARNING: The definition of recurrence used here is subtly different than
6366   // the one used by AddRec (and thus most of this file).  Step is allowed to
6367   // be arbitrarily loop varying here, where AddRec allows only loop invariant
6368   // and other addrecs in the same loop (for non-affine addrecs).  The code
6369   // below intentionally handles the case where step is not loop invariant.
6370   auto *P = dyn_cast<PHINode>(U->getValue());
6371   if (!P)
6372     return FullSet;
6373 
6374   // Make sure that no Phi input comes from an unreachable block. Otherwise,
6375   // even the values that are not available in these blocks may come from them,
6376   // and this leads to false-positive recurrence test.
6377   for (auto *Pred : predecessors(P->getParent()))
6378     if (!DT.isReachableFromEntry(Pred))
6379       return FullSet;
